/// Create routes for state transitions.
pub fn create_upload_session_transition_routes(service: Arc<UploadSessionService>) -> Router {
    use axum::routing::post;

    Router::new()
        .route("/upload_sessions/:id/transitions/start_upload", post(start_upload_transition))
        .route("/upload_sessions/:id/transitions/add_part", post(add_part_transition))
        .route("/upload_sessions/:id/transitions/complete", post(complete_transition))
        .route("/upload_sessions/:id/transitions/finish", post(finish_transition))
        .route("/upload_sessions/:id/transitions/fail", post(fail_transition))
        .route("/upload_sessions/:id/transitions/abort", post(abort_transition))
        .route("/upload_sessions/:id/transitions/expire", post(expire_transition))
        .route("/upload_sessions/:id/transitions/retry", post(retry_transition))
        .with_state(service)
}

